#include "./main.h"
#include <math.h>

void kernel_gpu_openmp(
    params_common d_common,					
    fp* d_frame,					
    int d_frame_no,							
    int* d_endoRow,				
    int* d_endoCol,				
    int* d_tEndoRowLoc,			
    int* d_tEndoColLoc,			
    int* d_epiRow,					
    int* d_epiCol,					
    int* d_tEpiRowLoc,				
    int* d_tEpiColLoc,				
    fp* d_endoT,					
    fp* d_epiT,					
    fp* d_in2_all,					
    fp* d_conv_all,				
    fp* d_in2_pad_cumv_all,		
    fp* d_in2_pad_cumv_sel_all,	
    fp* d_in2_sub_cumh_all,		
    fp* d_in2_sub_cumh_sel_all,	
    fp* d_in2_sub2_all,			
    fp* d_in2_sqr_all,				
    fp* d_in2_sqr_sub2_all,		
    fp* d_in_sqr_all,				
    fp* d_tMask_all,				
    fp* d_mask_conv_all,			
    fp* d_in_mod_temp_all,			
    fp* in_partial_sum_all,		
    fp* in_sqr_partial_sum_all,	
    fp* par_max_val_all,			
    int* par_max_coo_all,			
    fp* in_final_sum_all,			
    fp* in_sqr_final_sum_all,		
    fp* denomT_all,				
    fp* checksum)					
{
    int bx_max = d_common.endoPoints + d_common.epiPoints;
    int NUMBER_THREADS_local = NUMBER_THREADS;

    #pragma omp parallel
    {
        int bx, tx;
        bx = omp_get_thread_num() / NUMBER_THREADS_local;
        tx = omp_get_thread_num() % NUMBER_THREADS_local;

        if(bx >= bx_max) return;

        int d_unique_point_no;
        int* d_unique_d_Row;
        int* d_unique_d_Col;
        int* d_unique_d_tRowLoc;
        int* d_unique_d_tColLoc;
        fp* d_in;

        if(bx < d_common.endoPoints){
            d_unique_point_no = bx;
            d_unique_d_Row = d_endoRow;
            d_unique_d_Col = d_endoCol;
            d_unique_d_tRowLoc = d_tEndoRowLoc;
            d_unique_d_tColLoc = d_tEndoColLoc;
            d_in = &d_endoT[d_unique_point_no * d_common.in_elem];
        }
        else{
            d_unique_point_no = bx - d_common.endoPoints;
            d_unique_d_Row = d_epiRow;
            d_unique_d_Col = d_epiCol;
            d_unique_d_tRowLoc = d_tEpiRowLoc;
            d_unique_d_tColLoc = d_tEpiColLoc;
            d_in = &d_epiT[d_unique_point_no * d_common.in_elem];
        }

        fp* d_unique_d_in2 = &d_in2_all[bx*d_common.in2_elem];
        fp* d_unique_d_conv = &d_conv_all[bx*d_common.conv_elem];
        fp* d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx*d_common.in2_pad_cumv_elem];
        fp* d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx*d_common.in2_pad_cumv_sel_elem];
        fp* d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx*d_common.in2_sub_cumh_elem];
        fp* d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx*d_common.in2_sub_cumh_sel_elem];
        fp* d_unique_d_in2_sub2 = &d_in2_sub2_all[bx*d_common.in2_sub2_elem];
        fp* d_unique_d_in2_sqr = &d_in2_sqr_all[bx*d_common.in2_sqr_elem];
        fp* d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx*d_common.in2_sqr_sub2_elem];
        fp* d_unique_d_in_sqr = &d_in_sqr_all[bx*d_common.in_sqr_elem];
        fp* d_unique_d_tMask = &d_tMask_all[bx*d_common.tMask_elem];
        fp* d_unique_d_mask_conv = &d_mask_conv_all[bx*d_common.mask_conv_elem];

        fp* d_in_mod_temp = &d_in_mod_temp_all[bx*d_common.in_elem];
        fp* in_partial_sum = &in_partial_sum_all[bx*d_common.in_cols];
        fp* in_sqr_partial_sum = &in_sqr_partial_sum_all[bx*d_common.in_sqr_rows];
        fp* par_max_val = &par_max_val_all[bx*d_common.mask_conv_rows];
        int* par_max_coo = &par_max_coo_all[bx*d_common.mask_conv_rows];

        fp* in_final_sum = &in_final_sum_all[bx];
        fp* in_sqr_final_sum = &in_sqr_final_sum_all[bx];
        fp* denomT = &denomT_all[bx];

#ifdef TEST_CHECKSUM
        if(bx==0 && tx==0){
            for(int i=0; i<CHECK; i++){
                checksum[i] = 0;
            }
        }
#endif

        if(d_frame_no == 0){
#ifdef INIT
            if(tx == 0){
                for(int i=0; i<d_common.no_frames; i++){
                    d_unique_d_tRowLoc[d_unique_point_no*d_common.no_frames+i] = 0;
                    d_unique_d_tColLoc[d_unique_point_no*d_common.no_frames+i] = 0;
                }
                for(int i=0; i<d_common.in_elem; i++){
                    d_in[i] = 0;
                }
            }
#endif
            #pragma omp barrier

            if(tx == 0){
                int pointer = d_unique_point_no*d_common.no_frames + d_frame_no;
                d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
                d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];
            }

            for(int ei_new=tx; ei_new < d_common.in_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in_rows - 1;
                int col = (ei_new+1) / d_common.in_rows;
                if((ei_new+1) % d_common.in_rows == 0){
                    row = d_common.in_rows - 1;
                    col = col -1;
                }
                col = col - 1;

                int ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
                int ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
                int ori_pointer = ori_col*d_common.frame_rows + ori_row;
                d_in[col*d_common.in_rows + row] = d_frame[ori_pointer];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in_elem; i++){
                    checksum[0] = checksum[0]+d_in[i];
                }
            }
            #pragma omp barrier
#endif
        }

        if(d_frame_no != 0){
#ifdef INIT
            if(tx == 0){
                for(int i=0; i<d_common.in2_elem; i++) d_unique_d_in2[i] = 0;
                for(int i=0; i<d_common.conv_elem; i++) d_unique_d_conv[i] = 0;
                for(int i=0; i<d_common.in2_pad_cumv_elem; i++) d_unique_d_in2_pad_cumv[i] = 0;
                for(int i=0; i<d_common.in2_pad_cumv_sel_elem; i++) d_unique_d_in2_pad_cumv_sel[i] = 0;
                for(int i=0; i<d_common.in2_sub_cumh_elem; i++) d_unique_d_in2_sub_cumh[i] = 0;
                for(int i=0; i<d_common.in2_sub_cumh_sel_elem; i++) d_unique_d_in2_sub_cumh_sel[i] = 0;
                for(int i=0; i<d_common.in2_sub2_elem; i++) d_unique_d_in2_sub2[i] = 0;
                for(int i=0; i<d_common.in2_sqr_elem; i++) d_unique_d_in2_sqr[i] = 0;
                for(int i=0; i<d_common.in2_sqr_sub2_elem; i++) d_unique_d_in2_sqr_sub2[i] = 0;
                for(int i=0; i<d_common.in_sqr_elem; i++) d_unique_d_in_sqr[i] = 0;
                for(int i=0; i<d_common.tMask_elem; i++) d_unique_d_tMask[i] = 0;
                for(int i=0; i<d_common.mask_conv_elem; i++) d_unique_d_mask_conv[i] = 0;
                for(int i=0; i<d_common.in_elem; i++) d_in_mod_temp[i] = 0;
                for(int i=0; i<d_common.in_cols; i++) in_partial_sum[i] = 0;
                for(int i=0; i<d_common.in_sqr_rows; i++) in_sqr_partial_sum[i] = 0;
                for(int i=0; i<d_common.mask_conv_rows; i++) par_max_val[i] = 0;
                for(int i=0; i<d_common.mask_conv_rows; i++) par_max_coo[i] = 0;
                in_final_sum[0] = 0;
                in_sqr_final_sum[0] = 0;
                denomT[0] = 0;
            }
#endif
            #pragma omp barrier

            int in2_rowlow = d_unique_d_Row[d_unique_point_no] - d_common.sSize;
            int in2_collow = d_unique_d_Col[d_unique_point_no] - d_common.sSize;

            for(int ei_new=tx; ei_new < d_common.in2_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in2_rows - 1;
                int col = (ei_new+1) / d_common.in2_rows;
                if((ei_new+1) % d_common.in2_rows == 0){
                    row = d_common.in2_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                int ori_row = row + in2_rowlow - 1;
                int ori_col = col + in2_collow - 1;
                d_unique_d_in2[ei_new] = d_frame[ori_col*d_common.frame_rows + ori_row];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_elem; i++){
                    checksum[1] = checksum[1]+d_unique_d_in2[i];
                }
            }
            #pragma omp barrier
#endif

            // Rotate and copy d_in to d_in_mod_temp
            for(int ei_new=tx; ei_new < d_common.in_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in_rows - 1;
                int col = (ei_new+1) / d_common.in_rows;
                if((ei_new+1) % d_common.in_rows == 0){
                    row = d_common.in_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                int rot_row = (d_common.in_rows-1) - row;
                int rot_col = (d_common.in_rows-1) - col;
                d_in_mod_temp[ei_new] = d_in[rot_col*d_common.in_rows + rot_row];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in_elem; i++){
                    checksum[2] = checksum[2] + d_in_mod_temp[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.conv_elem; ei_new += NUMBER_THREADS_local){
                int ic = (ei_new+1) % d_common.conv_rows;
                int jc = (ei_new+1) / d_common.conv_rows;
                if((ei_new+1) % d_common.conv_rows == 0){
                    ic = d_common.conv_rows;
                    jc = jc - 1;
                }
                jc = jc - 1;

                int j = jc + d_common.joffset;
                int jp1 = j + 1;
                int ja1 = (d_common.in2_cols < jp1) ? (jp1 - d_common.in2_cols) : 1;
                int ja2 = (d_common.in_cols < j) ? d_common.in_cols : j;

                int i = ic + d_common.ioffset;
                int ip1 = i + 1;
                int ia1 = (d_common.in2_rows < ip1) ? (ip1 - d_common.in2_rows) : 1;
                int ia2 = (d_common.in_rows < i) ? d_common.in_rows : i;

                fp s = 0;

                for(int ja=ja1; ja<=ja2; ja++){
                    int jb = jp1 - ja;
                    for(int ia=ia1; ia<=ia2; ia++){
                        int ib = ip1 - ia;
                        s += d_in_mod_temp[d_common.in_rows*(ja-1) + ia-1] * d_unique_d_in2[d_common.in2_rows*(jb-1) + ib-1];
                    }
                }

                d_unique_d_conv[ei_new] = s;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.conv_elem; i++){
                    checksum[3] = checksum[3] + d_unique_d_conv[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_pad_cumv_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in2_pad_cumv_rows - 1;
                int col = (ei_new+1) / d_common.in2_pad_cumv_rows;
                if((ei_new+1) % d_common.in2_pad_cumv_rows == 0){
                    row = d_common.in2_pad_cumv_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                if(row > (d_common.in2_pad_add_rows - 1) &&
                   row < (d_common.in2_pad_add_rows + d_common.in2_rows) &&
                   col > (d_common.in2_pad_add_cols - 1) &&
                   col < (d_common.in2_pad_add_cols + d_common.in2_cols)){
                    int ori_row = row - d_common.in2_pad_add_rows;
                    int ori_col = col - d_common.in2_pad_add_cols;
                    d_unique_d_in2_pad_cumv[ei_new] = d_unique_d_in2[ori_col * d_common.in2_rows + ori_row];
                } else {
                    d_unique_d_in2_pad_cumv[ei_new] = 0;
                }
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_pad_cumv_elem; i++){
                    checksum[4] = checksum[4] + d_unique_d_in2_pad_cumv[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_pad_cumv_cols; ei_new += NUMBER_THREADS_local){
                int pos_ori = ei_new * d_common.in2_pad_cumv_rows;
                fp sum = 0;
                for(int position = pos_ori; position < pos_ori + d_common.in2_pad_cumv_rows; position++){
                    d_unique_d_in2_pad_cumv[position] += sum;
                    sum = d_unique_d_in2_pad_cumv[position];
                }
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_pad_cumv_cols; i++){
                    checksum[5] = checksum[5] + d_unique_d_in2_pad_cumv[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_pad_cumv_sel_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in2_pad_cumv_sel_rows - 1;
                int col = (ei_new+1) / d_common.in2_pad_cumv_sel_rows;
                if((ei_new+1) % d_common.in2_pad_cumv_sel_rows == 0){
                    row = d_common.in2_pad_cumv_sel_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                int ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
                int ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
                d_unique_d_in2_pad_cumv_sel[ei_new] = d_unique_d_in2_pad_cumv[ori_col * d_common.in2_pad_cumv_rows + ori_row];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_pad_cumv_sel_elem; i++){
                    checksum[6] = checksum[6] + d_unique_d_in2_pad_cumv_sel[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub_cumh_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in2_sub_cumh_rows - 1;
                int col = (ei_new+1) / d_common.in2_sub_cumh_rows;
                if((ei_new+1) % d_common.in2_sub_cumh_rows == 0){
                    row = d_common.in2_sub_cumh_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                int ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
                int ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
                d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv[ori_col * d_common.in2_pad_cumv_rows + ori_row];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub_cumh_elem; i++){
                    checksum[7] = checksum[7] + d_unique_d_in2_sub_cumh[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub_cumh_elem; ei_new += NUMBER_THREADS_local){
                d_unique_d_in2_sub_cumh[ei_new] = d_unique_d_in2_pad_cumv_sel[ei_new] - d_unique_d_in2_sub_cumh[ei_new];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub_cumh_elem; i++){
                    checksum[8] = checksum[8] + d_unique_d_in2_sub_cumh[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub_cumh_rows; ei_new += NUMBER_THREADS_local){
                int pos_ori = ei_new;
                fp sum = 0;
                for(int position = pos_ori; position < pos_ori + d_common.in2_sub_cumh_elem; position += d_common.in2_sub_cumh_rows){
                    d_unique_d_in2_sub_cumh[position] += sum;
                    sum = d_unique_d_in2_sub_cumh[position];
                }
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub_cumh_elem; i++){
                    checksum[9] = checksum[9] + d_unique_d_in2_sub_cumh[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub_cumh_sel_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in2_sub_cumh_sel_rows - 1;
                int col = (ei_new+1) / d_common.in2_sub_cumh_sel_rows;
                if((ei_new+1) % d_common.in2_sub_cumh_sel_rows == 0){
                    row = d_common.in2_sub_cumh_sel_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                int ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
                int ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
                d_unique_d_in2_sub_cumh_sel[ei_new] = d_unique_d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub_cumh_sel_elem; i++){
                    checksum[10] = checksum[10] + d_unique_d_in2_sub_cumh_sel[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub2_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in2_sub2_rows - 1;
                int col = (ei_new+1) / d_common.in2_sub2_rows;
                if((ei_new+1) % d_common.in2_sub2_rows == 0){
                    row = d_common.in2_sub2_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                int ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
                int ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
                d_unique_d_in2_sub2[ei_new] = d_unique_d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub2_elem; i++){
                    checksum[11] = checksum[11] + d_unique_d_in2_sub2[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub2_elem; ei_new += NUMBER_THREADS_local){
                d_unique_d_in2_sub2[ei_new] = d_unique_d_in2_sub_cumh_sel[ei_new] - d_unique_d_in2_sub2[ei_new];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub2_elem; i++){
                    checksum[12] = checksum[12] + d_unique_d_in2_sub2[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub2_elem; ei_new += NUMBER_THREADS_local){
                fp temp = d_unique_d_in2_sub2[ei_new];
                fp temp2 = d_unique_d_in2_sqr_sub2[ei_new] - (temp * temp / d_common.in_elem);
                if(temp2 < 0) temp2 = 0;
                d_unique_d_in2_sqr_sub2[ei_new] = sqrt(temp2);
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub2_elem; i++){
                    checksum[13] = checksum[13] + d_unique_d_in2_sqr_sub2[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in_sqr_elem; ei_new += NUMBER_THREADS_local){
                fp temp = d_in[ei_new];
                d_unique_d_in_sqr[ei_new] = temp * temp;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in_sqr_elem; i++){
                    checksum[14] = checksum[14] + d_unique_d_in_sqr[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in_cols; ei_new += NUMBER_THREADS_local){
                fp sum = 0;
                for(int i=0; i<d_common.in_rows; i++){
                    sum += d_in[ei_new * d_common.in_rows + i];
                }
                in_partial_sum[ei_new] = sum;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in_cols; i++){
                    checksum[15] = checksum[15] + in_partial_sum[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in_sqr_rows; ei_new += NUMBER_THREADS_local){
                fp sum = 0;
                for(int i=0; i<d_common.in_sqr_cols; i++){
                    sum += d_unique_d_in_sqr[ei_new + d_common.in_sqr_rows * i];
                }
                in_sqr_partial_sum[ei_new] = sum;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in_sqr_rows; i++){
                    checksum[16] = checksum[16] + in_sqr_partial_sum[i];
                }
            }
            #pragma omp barrier
#endif

            if(tx == 0){
                in_final_sum[0] = 0;
                for(int i=0; i<d_common.in_cols; i++){
                    in_final_sum[0] += in_partial_sum[i];
                }
            } else if(tx == 1){
                in_sqr_final_sum[0] = 0;
                for(int i=0; i<d_common.in_sqr_cols; i++){
                    in_sqr_final_sum[0] += in_sqr_partial_sum[i];
                }
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                checksum[17] = checksum[17] + in_final_sum[0] + in_sqr_final_sum[0];
            }
            #pragma omp barrier
#endif

            if(tx == 0){
                fp mean = in_final_sum[0] / d_common.in_elem;
                fp mean_sqr = mean * mean;
                fp variance = (in_sqr_final_sum[0] / d_common.in_elem) - mean_sqr;
                fp deviation = sqrt(variance);
                denomT[0] = sqrt((fp)(d_common.in_elem-1)) * deviation;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                checksum[18] = checksum[18] + denomT[0];
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub2_elem; ei_new += NUMBER_THREADS_local){
                d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * denomT[0];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub2_elem; i++){
                    checksum[19] = checksum[19] + d_unique_d_in2_sqr_sub2[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.conv_elem; ei_new += NUMBER_THREADS_local){
                d_unique_d_conv[ei_new] = d_unique_d_conv[ei_new] - d_unique_d_in2_sub2[ei_new] * in_final_sum[0] / d_common.in_elem;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.conv_elem; i++){
                    checksum[20] = checksum[20] + d_unique_d_conv[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.in2_sub2_elem; ei_new += NUMBER_THREADS_local){
                d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_conv[ei_new] / d_unique_d_in2_sqr_sub2[ei_new];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in2_sub2_elem; i++){
                    checksum[21] = checksum[21] + d_unique_d_in2_sqr_sub2[i];
                }
            }
            #pragma omp barrier
#endif

            int cent = d_common.sSize + d_common.tSize + 1;
            int pointer;
            int tMask_row, tMask_col;

            if(d_frame_no == 0){
                tMask_row = cent + d_unique_d_Row[d_unique_point_no] - d_unique_d_Row[d_unique_point_no] - 1;
                tMask_col = cent + d_unique_d_Col[d_unique_point_no] - d_unique_d_Col[d_unique_point_no] - 1;
            } else {
                pointer = d_unique_point_no*d_common.no_frames + d_frame_no - 1;
                tMask_row = cent + d_unique_d_tRowLoc[pointer] - d_unique_d_Row[d_unique_point_no] - 1;
                tMask_col = cent + d_unique_d_tColLoc[pointer] - d_unique_d_Col[d_unique_point_no] - 1;
            }

            for(int ei_new=tx; ei_new < d_common.tMask_elem; ei_new += NUMBER_THREADS_local){
                int location = tMask_col * d_common.tMask_rows + tMask_row;
                d_unique_d_tMask[ei_new] = (ei_new == location) ? 1 : 0;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.tMask_elem; i++){
                    checksum[22] = checksum[22] + d_unique_d_tMask[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.mask_conv_elem; ei_new += NUMBER_THREADS_local){
                int ic = (ei_new+1) % d_common.mask_conv_rows;
                int jc = (ei_new+1) / d_common.mask_conv_rows;
                if((ei_new+1) % d_common.mask_conv_rows == 0){
                    ic = d_common.mask_conv_rows;
                    jc = jc - 1;
                }
                jc = jc - 1;

                int j = jc + d_common.mask_conv_joffset;
                int jp1 = j + 1;
                int ja1 = (d_common.mask_cols < jp1) ? (jp1 - d_common.mask_cols) : 1;
                int ja2 = (d_common.tMask_cols < j) ? d_common.tMask_cols : j;

                int i = ic + d_common.mask_conv_ioffset;
                int ip1 = i + 1;
                int ia1 = (d_common.mask_rows < ip1) ? (ip1 - d_common.mask_rows) : 1;
                int ia2 = (d_common.tMask_rows < i) ? d_common.tMask_rows : i;

                fp s = 0;

                for(int ja=ja1; ja<=ja2; ja++){
                    int jb = jp1 - ja;
                    for(int ia=ia1; ia<=ia2; ia++){
                        int ib = ip1 - ia;
                        s += d_unique_d_tMask[d_common.tMask_rows*(ja-1) + ia-1] * 1;
                    }
                }

                d_unique_d_mask_conv[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * s;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.mask_conv_elem; i++){
                    checksum[23] = checksum[23] + d_unique_d_mask_conv[i];
                }
            }
            #pragma omp barrier
#endif

            for(int ei_new=tx; ei_new < d_common.mask_conv_rows; ei_new += NUMBER_THREADS_local){
                fp largest_value = 0;
                int largest_coordinate = 0;
                for(int i=0; i<d_common.mask_conv_cols; i++){
                    int idx = ei_new * d_common.mask_conv_cols + i;
                    fp val = fabs(d_unique_d_mask_conv[idx]);
                    if(val > largest_value){
                        largest_value = val;
                        largest_coordinate = idx;
                    }
                }
                par_max_coo[ei_new] = largest_coordinate;
                par_max_val[ei_new] = largest_value;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.mask_conv_rows; i++){
                    checksum[24] = checksum[24] + par_max_coo[i] + par_max_val[i];
                }
            }
            #pragma omp barrier
#endif

            if(tx == 0){
                fp fin_max_val = 0;
                int fin_max_coo = 0;
                for(int i=0; i<d_common.mask_conv_rows; i++){
                    if(par_max_val[i] > fin_max_val){
                        fin_max_val = par_max_val[i];
                        fin_max_coo = par_max_coo[i];
                    }
                }
                int largest_row = (fin_max_coo + 1) % d_common.mask_conv_rows - 1;
                int largest_col = (fin_max_coo + 1) / d_common.mask_conv_rows;
                if((fin_max_coo + 1) % d_common.mask_conv_rows == 0){
                    largest_row = d_common.mask_conv_rows - 1;
                    largest_col -= 1;
                }
                largest_row += 1;
                largest_col += 1;
                int offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
                int offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
                int pointer = d_unique_point_no*d_common.no_frames + d_frame_no;
                d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no] + offset_row;
                d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no] + offset_col;
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                int pointer = d_unique_point_no*d_common.no_frames + d_frame_no;
                checksum[25] = checksum[25] + d_unique_d_tRowLoc[pointer] + d_unique_d_tColLoc[pointer];
            }
            #pragma omp barrier
#endif
        }

        if(d_frame_no != 0 && (d_frame_no % 10) == 0){
#ifdef INIT
            if(tx==0){
                for(int i=0; i<d_common.in_elem; i++){
                    d_in[i] = 0;
                }
            }
#endif
            #pragma omp barrier

            int loc_pointer = d_unique_point_no*d_common.no_frames + d_frame_no;
            d_unique_d_Row[d_unique_point_no] = d_unique_d_tRowLoc[loc_pointer];
            d_unique_d_Col[d_unique_point_no] = d_unique_d_tColLoc[loc_pointer];

            for(int ei_new=tx; ei_new < d_common.in_elem; ei_new += NUMBER_THREADS_local){
                int row = (ei_new+1) % d_common.in_rows - 1;
                int col = (ei_new+1) / d_common.in_rows;
                if((ei_new+1) % d_common.in_rows == 0){
                    row = d_common.in_rows - 1;
                    col = col - 1;
                }
                col = col - 1;

                int ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
                int ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
                int ori_pointer = ori_col*d_common.frame_rows + ori_row;

                d_in[ei_new] = d_common.alpha*d_in[ei_new] + (1 - d_common.alpha)*d_frame[ori_pointer];
            }

            #pragma omp barrier

#ifdef TEST_CHECKSUM
            if(bx==0 && tx==0){
                for(int i=0; i<d_common.in_elem; i++){
                    checksum[26] = checksum[26] + d_in[i];
                }
            }
            #pragma omp barrier
#endif
        }
    }
